import { useContext, useState } from 'react';
import { useForm } from 'react-hook-form';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { AuthContext } from '../../context/';

import Navbar from '../UI/navbar/Navbar';

const Login = () => {
  const { setIsAuth } = useContext(AuthContext);
  const navigate = useNavigate();
  const [error, setError] = useState('');

  const { register, handleSubmit, formState: { errors } } = useForm();

  const onSubmit = async (data) => {
    try {
      const response = await axios.post(`${process.env.REACT_APP_API_URL}/api/login`, data);

      if (response.data.message === 'Login riuscito') {
        const userData = {
          username: response.data.username,
          categoria: response.data.categoria
        };

        localStorage.setItem('auth', 'true');
        localStorage.setItem('user', JSON.stringify(userData));

        setIsAuth(true);
        setError('');
        navigate('/generale');
      } else {
        setError('Неверный логин или пароль');
      }
    } catch (err) {
      console.error(err);
      setError('Ошибка соединения с сервером');
    }
  };

  return (
    <div>
      <Navbar />
      <h2>Login</h2>
      {error && <p style={{ color: 'red' }}>{error}</p>}
      <form onSubmit={handleSubmit(onSubmit)}>
        <div>
          <input
            type="text"
            placeholder="Username"
            {...register('username', { required: 'Username obbligatorio' })}
          />
          {errors.username && <p>{errors.username.message}</p>}
        </div>
        <div>
          <input
            type="password"
            placeholder="Password"
            {...register('password', { required: 'Password obbligatoria' })}
          />
          {errors.password && <p>{errors.password.message}</p>}
        </div>
        <button type="submit">Login</button>
      </form>
    </div>
  );
};

export default Login;
